import 'dart:io';

void main() {
  int n = int.parse(stdin.readLineSync()!);

  if (n < 2) {
    print('Không nguyên tố');
    return;
  }

  bool isPrime = true;
  for (int i = 2; i * i <= n; i++) {
    if (n % i == 0) {
      isPrime = false;
      break;
    }
  }

  print(isPrime ? 'Nguyên tố' : 'Không nguyên tố');
}

